class Person:
    def __init__(self, förnamn, efternamn, födelseår):
        self.förnamn = förnamn
        self.efternamn = efternamn
        self.födelseår = födelseår
    def skrivIntro(self):
        print("Hej jag heter " + self.förnamn + " " + self.efternamn + " och jag är född " + str(self.födelseår) + " år gammal")

kim = Person("Kim","Efternamnsson", 1993)
print(kim)
